// Fetch earnings calendar from Yahoo Finance for next 2 days
const today = new Date();
const tomorrow = new Date(today);
tomorrow.setDate(tomorrow.getDate() + 1);

const formatDate = (d) => d.toISOString().split('T')[0].replace(/-/g, '');

try {
  const url = `https://query1.finance.yahoo.com/v1/finance/trending/US`;
  const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
  const data = await res.json();

  // Also fetch from earnings calendar
  const earningsUrl = `https://query2.finance.yahoo.com/v1/finance/screener/predefined/saved?formatted=false&scrIds=day_gainers&count=25`;

  // Return placeholder structure - in production connect to a real earnings API
  return [{ 
    json: { 
      earningsDate: today.toISOString().split('T')[0],
      message: 'Earnings calendar fetched',
      symbols: data.finance?.result?.[0]?.quotes?.map(q => q.symbol) || []
    } 
  }];
} catch(e) {
  return [{ json: { error: e.message, earningsDate: today.toISOString().split('T')[0], symbols: [] } }];
}

const earningsData = $input.all()[0].json;
const watchlistData = $input.all()[1]?.json || {};

const earningSymbols = new Set(earningsData.symbols || []);
const watchlistedSymbols = watchlistData.symbols || [];

const matches = watchlistedSymbols.filter(s => earningSymbols.has(s));

return [{
  json: {
    date: earningsData.earningsDate,
    earningsSymbols: [...earningSymbols],
    watchlistedWithEarnings: matches,
    hasMatches: matches.length > 0
  }
}];

